// ================================
// ADMIN PANEL
// ================================

import React, { useState, useEffect } from 'react';
import { CheckCircle, XCircle, Clock, Wallet, TrendingUp, Users } from 'lucide-react';
import api from '../services/api';

export default function AdminPanel() {
  const [pendingDeposits, setPendingDeposits] = useState([]);
  const [stats, setStats] = useState({ totalDeposits: 0, totalDepositAmount: 0, pendingDeposits: 0 });
  const [loading, setLoading] = useState(false);
  const [approvalLoading, setApprovalLoading] = useState({});
  const [rejectionReason, setRejectionReason] = useState({});
  const [message, setMessage] = useState('');

  useEffect(() => {
    loadPendingDeposits();
    loadStats();
  }, []);

  const loadStats = async () => {
    try {
      const response = await api.get('/admin/stats/dashboard');
      setStats(response);
    } catch (error) {
      console.error('Error loading stats:', error);
    }
  };

  const loadPendingDeposits = async () => {
    setLoading(true);
    try {
      const response = await api.get('/admin/deposits/pending');
      setPendingDeposits(response.deposits || []);
    } catch (error) {
      console.error('Error loading deposits:', error);
      setMessage({ type: 'error', text: 'Failed to load pending deposits. Make sure you have admin access.' });
    } finally {
      setLoading(false);
    }
  };

  const handleApproveDeposit = async (depositId) => {
    setApprovalLoading({ ...approvalLoading, [depositId]: true });
    try {
      const response = await api.put(`/admin/deposits/${depositId}/approve`, {});
      setMessage({ type: 'success', text: 'Deposit approved successfully!' });
      setPendingDeposits(pendingDeposits.filter(d => d._id !== depositId));
      loadStats();
      setTimeout(() => setMessage(''), 3000);
    } catch (error) {
      setMessage({ type: 'error', text: error.response?.data?.error || 'Error approving deposit' });
    } finally {
      setApprovalLoading({ ...approvalLoading, [depositId]: false });
    }
  };

  const handleRejectDeposit = async (depositId) => {
    const reason = rejectionReason[depositId] || 'No reason provided';
    setApprovalLoading({ ...approvalLoading, [depositId]: true });
    try {
      const response = await api.put(`/admin/deposits/${depositId}/reject`, { reason });
      setMessage({ type: 'success', text: 'Deposit rejected successfully!' });
      setPendingDeposits(pendingDeposits.filter(d => d._id !== depositId));
      loadStats();
      setTimeout(() => setMessage(''), 3000);
    } catch (error) {
      setMessage({ type: 'error', text: error.response?.data?.error || 'Error rejecting deposit' });
    } finally {
      setApprovalLoading({ ...approvalLoading, [depositId]: false });
    }
  };

  const getMethodIcon = (method) => {
    const icons = {
      opay: '💳',
      naira: '₦',
      bank_transfer: '🏦',
      bitcoin: '₿',
      ethereum: 'Ξ',
      usdt_trc20: '🪙',
      usdt_bep20: '🪙',
      bnb: '🔶',
      card: '💳',
    };
    return icons[method] || '💰';
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-900 via-gray-800 to-black p-4 md:p-8">
      {/* Header */}
      <div className="max-w-7xl mx-auto">
        <div className="mb-8">
          <h1 className="text-4xl font-bold text-white mb-2">Admin Dashboard</h1>
          <p className="text-gray-400">Manage deposits, users, and platform settings</p>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          <div className="bg-gradient-to-br from-blue-600 to-blue-700 rounded-lg p-6 text-white">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-gray-200 text-sm">Total Deposits</p>
                <h3 className="text-3xl font-bold">{stats.totalDeposits}</h3>
              </div>
              <Wallet size={40} className="opacity-50" />
            </div>
          </div>

          <div className="bg-gradient-to-br from-green-600 to-green-700 rounded-lg p-6 text-white">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-gray-200 text-sm">Total Amount</p>
                <h3 className="text-3xl font-bold">${stats.totalDepositAmount.toLocaleString()}</h3>
              </div>
              <TrendingUp size={40} className="opacity-50" />
            </div>
          </div>

          <div className="bg-gradient-to-br from-yellow-600 to-yellow-700 rounded-lg p-6 text-white">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-gray-200 text-sm">Pending Review</p>
                <h3 className="text-3xl font-bold">{stats.pendingDeposits}</h3>
              </div>
              <Clock size={40} className="opacity-50" />
            </div>
          </div>
        </div>

        {/* Message */}
        {message && (
          <div className={`mb-6 p-4 rounded-lg ${message.type === 'success' ? 'bg-green-500/20 text-green-400 border border-green-500' : 'bg-red-500/20 text-red-400 border border-red-500'}`}>
            {message.text}
          </div>
        )}

        {/* Pending Deposits Section */}
        <div className="bg-gray-900/50 rounded-lg border border-gray-700 overflow-hidden">
          <div className="bg-gradient-to-r from-gray-800 to-gray-900 border-b border-gray-700 p-6">
            <h2 className="text-2xl font-bold text-white flex items-center gap-2">
              <Clock size={24} />
              Pending Deposits ({pendingDeposits.length})
            </h2>
          </div>

          <div className="p-6">
            {loading ? (
              <div className="text-center text-gray-400">
                <p>Loading pending deposits...</p>
              </div>
            ) : pendingDeposits.length === 0 ? (
              <div className="text-center text-gray-400">
                <CheckCircle size={48} className="mx-auto mb-4 opacity-50" />
                <p className="text-lg">No pending deposits! All deposits have been processed.</p>
              </div>
            ) : (
              <div className="space-y-4">
                {pendingDeposits.map((deposit) => (
                  <div key={deposit._id} className="bg-gray-800/50 border border-gray-700 rounded-lg p-6 hover:border-gray-600 transition">
                    {/* Deposit Info */}
                    <div className="grid grid-cols-1 md:grid-cols-6 gap-4 mb-6">
                      <div>
                        <p className="text-gray-400 text-sm">Method</p>
                        <p className="text-white text-lg font-semibold">
                          {getMethodIcon(deposit.method)} {deposit.method.replace('_', ' ').toUpperCase()}
                        </p>
                      </div>
                      <div>
                        <p className="text-gray-400 text-sm">Amount</p>
                        <p className="text-white text-lg font-semibold">
                          {deposit.currency === 'NAIRA' || deposit.method === 'naira' ? '₦' : '$'}{deposit.amount.toLocaleString()}
                        </p>
                      </div>
                      <div>
                        <p className="text-gray-400 text-sm">Currency</p>
                        <p className="text-white text-lg font-semibold">{deposit.currency || 'USD'}</p>
                      </div>
                      <div>
                        <p className="text-gray-400 text-sm">User ID</p>
                        <p className="text-white text-sm font-mono">{deposit.userId.substring(0, 12)}...</p>
                      </div>
                      <div>
                        <p className="text-gray-400 text-sm">Created</p>
                        <p className="text-white text-sm">{new Date(deposit.createdAt).toLocaleString()}</p>
                      </div>
                      <div>
                        <p className="text-gray-400 text-sm">Status</p>
                        <p className="text-yellow-400 text-lg font-semibold flex items-center gap-1">
                          <Clock size={16} /> PENDING
                        </p>
                      </div>
                    </div>

                    {/* Payment Details */}
                    {deposit.paymentDetails && (
                      <div className="bg-gray-900/50 rounded p-4 mb-6 border border-gray-700">
                        <p className="text-gray-400 text-sm mb-2">Payment Details:</p>
                        <div className="space-y-1 text-gray-300 text-sm">
                          {Object.entries(deposit.paymentDetails).map(([key, value]) => (
                            <div key={key} className="flex justify-between">
                              <span className="font-mono">{key}:</span>
                              <span>{value}</span>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}

                    {/* Transaction ID */}
                    <div className="bg-gray-900/50 rounded p-4 mb-6 border border-gray-700">
                      <p className="text-gray-400 text-sm">Transaction ID: <span className="text-gray-300 font-mono">{deposit.transactionId}</span></p>
                    </div>

                    {/* Rejection Reason */}
                    {approvalLoading[deposit._id] !== true && (
                      <div className="mb-6">
                        <label className="block text-gray-400 text-sm mb-2">Rejection Reason (if rejecting)</label>
                        <textarea
                          placeholder="Optional: Reason for rejection"
                          value={rejectionReason[deposit._id] || ''}
                          onChange={(e) => setRejectionReason({ ...rejectionReason, [deposit._id]: e.target.value })}
                          className="w-full bg-gray-900 border border-gray-700 rounded px-4 py-2 text-white text-sm focus:border-gray-600 focus:outline-none"
                          rows="2"
                        />
                      </div>
                    )}

                    {/* Action Buttons */}
                    <div className="flex gap-4 justify-end">
                      <button
                        onClick={() => handleRejectDeposit(deposit._id)}
                        disabled={approvalLoading[deposit._id]}
                        className="flex items-center gap-2 px-6 py-3 bg-red-600/20 text-red-400 border border-red-600 rounded-lg hover:bg-red-600/30 transition disabled:opacity-50"
                      >
                        <XCircle size={18} />
                        Reject
                      </button>
                      <button
                        onClick={() => handleApproveDeposit(deposit._id)}
                        disabled={approvalLoading[deposit._id]}
                        className="flex items-center gap-2 px-6 py-3 bg-green-600 text-white rounded-lg hover:bg-green-700 transition disabled:opacity-50"
                      >
                        <CheckCircle size={18} />
                        {approvalLoading[deposit._id] ? 'Approving...' : 'Approve'}
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
